/**
 * Self-registering entry point — importing this module augments the global
 * jQuery instance (`$` / `jQuery`) with all `$.fn.o9*` component plugins and
 * the overlay helpers.
 *
 * Usage (AMD / RequireJS):
 *   require(['@o9ds/js/auto'], function () {
 *     $('#my-btn').o9Button({ variant: 'primary' });
 *   });
 *
 * Usage (ES module):
 *   import '@o9ds/js/auto';
 *   $('#my-btn').o9Button({ variant: 'primary' });
 */
import $ from 'jquery';
import { registerO9Plugins } from './plugin';

registerO9Plugins($);
